#include<bits/stdc++.h>
using namespace std;

int solve(int n, vector<int> &times, vector<int> &scores, int t, int k) {
    int dp[n+1][t+1];
    memset(dp, 0, sizeof(dp));

    int ans = INT_MIN;
    int maxSoFar = INT_MIN;
    for (int i=1; i<=n; i++) {
        for (int j=1; j<=t; j++) {
            if (j >= times[i-1]) {
                dp[i][j] = max(dp[i-1][j], scores[i-1] + dp[i-1][j-times[i-1]]);
                if (maxSoFar < dp[i][j]) {
                    maxSoFar = dp[i][j];
                    ans = j;
                }
            }
            else {
                dp[i][j] = dp[i-1][j];
            }
        }
    }

    if (maxSoFar < k) {
        return -1;
    }
    return ans;
}

int main() {
    int n, t, k;
    cin>>n;

    vector<int> times(n), scores(n);

    for (int i=0; i<n; i++) {
        cin>>times[i];
        cin>>scores[i];
    }

    cin>>t>>k;

    cout<<solve(n, times, scores, t, k);

}

