def scoretime(arr, n, t, k):
    res = backtrack(arr, n, t, k, 0, 0, [])
    maxscore = 0
    time = 0
    for i, j in res:
        if j > maxscore:
            if maxscore == j:
                if time > i:
                    maxscore = j
                    time = i
            else:
                maxscore = j
                time = i
    return time

def backtrack(arr, n, timeallowed, minscore, time, score, output):
    if score >= minscore:
        output.append([time, score])
        #return
    for t, s in arr:
        time += t
        score += s
        if time <= timeallowed:
            backtrack(arr[1:], n, timeallowed, minscore, time, score, output)
        time -= t
        score -= s
    return output
